import{_ as e,o as a,c as s,a0 as i}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Intel X710和XL710 解锁 SFP模块限定","description":"","frontmatter":{"title":"Intel X710和XL710 解锁 SFP模块限定","date":"2021-4-6 21:31:9","category":"Home","tags":["驱动"]},"headers":[],"relativePath":"posts/Intel X710和XL710 解锁 SFP模块限定.md","filePath":"posts/Intel X710和XL710 解锁 SFP模块限定.md","lastUpdated":1783008259000}'),n={name:"posts/Intel X710和XL710 解锁 SFP模块限定.md"};function l(p,t,h,o,r,c){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h1><p>万兆网口卡中，Intel X520和X710用的比较多，虽然手头有一块X710，但一直没有启用，X520挺好用的，前几天同事说X710只能用Intel的SFP模块，不能用其他的比如华为SFP模块，感觉有点意思，就研究了下，这里做下记录，测试环境是Ubuntu 18.04，其他系统版本应该差不多。</p><h1 id="解锁原理" tabindex="-1">解锁原理 <a class="header-anchor" href="#解锁原理" aria-label="Permalink to &quot;解锁原理&quot;">​</a></h1><p>根据intel官方的 <a href="https://www.intel.com/content/dam/w...tasheets/xl710-10-40-controller-datasheet.pdf" target="_blank" rel="noreferrer">X710 Datasheet</a>，在NVM中有一个配置位会控制是否开启SFP模块准入。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617716520599.png" alt=""></p><p>解锁办法很简单，就是将这个地址数据的第11位清0即可。</p><h1 id="解锁步骤" tabindex="-1">解锁步骤 <a class="header-anchor" href="#解锁步骤" aria-label="Permalink to &quot;解锁步骤&quot;">​</a></h1><h3 id="_1、测试sfp模块是否兼容" tabindex="-1">1、测试SFP模块是否兼容 <a class="header-anchor" href="#_1、测试sfp模块是否兼容" aria-label="Permalink to &quot;1、测试SFP模块是否兼容&quot;">​</a></h3><p>ifconfig，看下网卡名，这里是enp1s0f0和enp1s0f1，SFP模块无法识别，指示灯也不亮，没有获取到IP。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617716677558.png" alt=""></p><h3 id="_2、更新固件" tabindex="-1">2、更新固件 <a class="header-anchor" href="#_2、更新固件" aria-label="Permalink to &quot;2、更新固件&quot;">​</a></h3><p>建议更新下网卡固件到最新版本，一般会修复一些bug，更新一些功能，当前是官方最新版本是<a href="https://downloadcenter.intel.com/zh-cn/download/24769/Ethernet-Non-Volatile-Memory-NVM-Update-Utility-for-Intel-Ethernet-Network-Adapter-710-Series?product=82947" target="_blank" rel="noreferrer">8.30版本合集</a>。</p><p>或者单独下载<a href="https://downloadcenter.intel.com/id/download/25791/-NVM-adapters-linux-" target="_blank" rel="noreferrer">Linux版本</a></p><p>解压830升级包，执行：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./nvmupdate64e</span></span></code></pre></div><p>如果要更详细的显示，可以执行：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./nvmupdate64e</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvmupdate.cfg</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617717017861.png" alt=""></p><p>如果询问是否备份时候选Y，会在当前目录下生成一个MAC地址名的文件夹，里面有备份的固件。</p><p>重启后生效：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvm</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617717040877.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617717074873.png" alt=""></p><h3 id="_3、找出修改位置" tabindex="-1">3、找出修改位置 <a class="header-anchor" href="#_3、找出修改位置" aria-label="Permalink to &quot;3、找出修改位置&quot;">​</a></h3><p>升级完成后，可以导出固件，方法有多种，这里先讲用ethtool导出：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ethtool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enp1s0f0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /root/nvm_830_0.txt</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617717134609.png" alt=""></p><p>检索<code>MAC地址</code>，比如检索<code>11 22 33 44 55 66</code>，在第三个地址的位置，大致如图所示：</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617717736578.png" alt=""></p><p>特征很明显，<code>0c 6b</code>就是目标位置，本质上是Datasheet中<code>6.3.24 PHY capability data structure 0 section summary table</code>的<code>0x0008</code>偏移。地址是<code>0xd280</code>，因为是16位地址，所以除以2换算得到<code>0x6940</code>。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718035605.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718049052.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718076143.png" alt=""></p><h3 id="_4、修改配置位" tabindex="-1">4、修改配置位 <a class="header-anchor" href="#_4、修改配置位" aria-label="Permalink to &quot;4、修改配置位&quot;">​</a></h3><p>国外有大咖提供了dump和改写的<a href="https://github.com/terpstra/xl710-unlocker" target="_blank" rel="noreferrer">工具</a></p><p>下载下来后，需要修改下源码文件。</p><p>首先看下网卡ID，Intel X710是<code>0x1572</code>，和官方介绍一致。</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lspci</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nn</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718229636.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718233820.png" alt=""></p><p>修改<code>mytool.c</code>文件，修改ID号和网卡名</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718345040.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718349781.png" alt=""></p><p>先make下，报错可以不管，会先生成<code>mytool</code>，可以用来读取nvm，读取<code>0x6940</code>地址开始的64个字节。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617719662123.png" alt=""></p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./mytool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x6940</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x40</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.txt</span></span></code></pre></div><p>可以看到和前面ethtool导出的是一致的，都是4个，因为x710最多有4个口，地址间距是0x0e</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718422183.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718426675.png" alt=""></p><p>修改第11位为0，也就是将<code>0x6b0c</code>改为<code>0x630c</code><code>0110 1011 0000 1100</code><code>0110 0011 0000 1100</code></p><p>修改<code>mypoke.c</code>文件，修改id、网卡名、地址、间隔、目标值 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718613413.png" alt=""></p><p><code>make</code>，然后运行<code>mypoke</code><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718656120.png" alt=""></p><p>检查一下，四个口的配置都改了</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./mytool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x6940</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x40</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1.txt</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718713043.png" alt=""></p><p>重启，已经可以识别华为SFP模块了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718743822.png" alt=""></p><h3 id="_5、降级与恢复" tabindex="-1">5、降级与恢复 <a class="header-anchor" href="#_5、降级与恢复" aria-label="Permalink to &quot;5、降级与恢复&quot;">​</a></h3><p>如果修改有问题，可以通过降级再升级、恢复默认配置来修复。</p><p>在Intel官方可以搜索降级包，但需要注意的时候，必须基于当前版本，比如搜索<a href="https://www.intel.com/content/www/us/en/search.html?ws=text#q=Intel%C2%AE%20Ethernet%20Adapters%20700%20Series%20downgrade%208.30&amp;t=Downloads&amp;layout=table" target="_blank" rel="noreferrer">8.30版本降级包</a> 关键字：<code>Intel® Ethernet Adapters 700 Series downgrade 8.30</code><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617718876556.png" alt=""></p><p>随便下一个，比如就<code>8.30-8.00</code></p><p>和升级一样，解压，运行<code>./nvmupdate64e</code>降级，<code>./nvmupdate64e -rd</code>恢复默认配置</p><h4 id="注意-如果修改好了网卡-后续再执行恢复默认配置的操作-配置位会恢复回去-需要重新改写。" tabindex="-1">注意：如果修改好了网卡，后续再执行恢复默认配置的操作，配置位会恢复回去，需要重新改写。 <a class="header-anchor" href="#注意-如果修改好了网卡-后续再执行恢复默认配置的操作-配置位会恢复回去-需要重新改写。" aria-label="Permalink to &quot;注意：如果修改好了网卡，后续再执行恢复默认配置的操作，配置位会恢复回去，需要重新改写。&quot;">​</a></h4><h1 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h1><p>升降级时候如果有备份固件，可以用hex编辑器打开看固件。</p><p>也可以直接用编程器读背面的Flash，可以读出固件改配置位完再写回去，很简单。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617719139587.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Intel_X710%E5%92%8CXL710_%E8%A7%A3%E9%94%81_SFP%E6%A8%A1%E5%9D%97%E9%99%90%E5%AE%9A/1617719226893.png" alt=""></p><p><a href="https://forums.servethehome.com/index.php?threads/unlocking-any-brand-sfp-modules-on-intel-x710.29040/" target="_blank" rel="noreferrer">参考网址1</a><a href="https://sourceforge.net/p/e1000/mailman/message/34988514/" target="_blank" rel="noreferrer">参考网址2</a></p>`,69)])])}const E=e(n,[["render",l]]);export{g as __pageData,E as default};
